const input = $json;

const systemPrompt = `# Rol
Eres el BMC Agent del sistema Innexia AI Strategic Analysis Engine v5.

# Objetivo
Construir el Business Model Canvas del proyecto analizado, usando el input original y el context_bundle entregado por el Supervisor Agent.

# Instrucciones
- Produce un Business Model Canvas claro, realista y accionable.
- Usa supuestos razonables cuando falten datos.
- Prioriza claridad de negocio, diferenciación y viabilidad.
- No expliques tu razonamiento.
- Devuelve únicamente JSON válido.

# Formato de salida
{
  "bmc": {
    "customer_segments": [],
    "value_propositions": [],
    "channels": [],
    "customer_relationships": [],
    "revenue_streams": [],
    "key_resources": [],
    "key_activities": [],
    "key_partners": [],
    "cost_structure": []
  },
  "positioning": {
    "problem_statement": "",
    "differentiators": [],
    "fit_score": 0,
    "assumptions": []
  }
}

# Regla final
Devuelve únicamente JSON válido.`;

const userPayload = JSON.stringify(input);

const outputSchema = {
  type: "object",
  properties: {
    bmc: {
      type: "object",
      properties: {
        customer_segments: { type: "array", items: { type: "string" } },
        value_propositions: { type: "array", items: { type: "string" } },
        channels: { type: "array", items: { type: "string" } },
        customer_relationships: { type: "array", items: { type: "string" } },
        revenue_streams: { type: "array", items: { type: "string" } },
        key_resources: { type: "array", items: { type: "string" } },
        key_activities: { type: "array", items: { type: "string" } },
        key_partners: { type: "array", items: { type: "string" } },
        cost_structure: { type: "array", items: { type: "string" } }
      },
      required: ["customer_segments", "value_propositions", "channels", "customer_relationships", "revenue_streams", "key_resources", "key_activities", "key_partners", "cost_structure"]
    },
    positioning: {
      type: "object",
      properties: {
        problem_statement: { type: "string" },
        differentiators: { type: "array", items: { type: "string" } },
        fit_score: { type: "number" },
        assumptions: { type: "array", items: { type: "string" } }
      },
      required: ["problem_statement", "differentiators", "fit_score", "assumptions"]
    }
  },
  required: ["bmc", "positioning"]
};

return [{ json: { input, system_prompt: systemPrompt, user_payload: userPayload, output_schema: outputSchema } }];

let content = $json.text ?? $json.output ?? $json;

if (typeof content === 'string') {
  content = content.trim();

  if (content.startsWith('```')) {
    content = content
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/, '')
      .replace(/```$/, '')
      .trim();
  }

  content = JSON.parse(content);
}

if (content && typeof content === 'object' && content.__structured__output__object) {
  content = content.__structured__output__object;
}

content.bmc = content.bmc || {};
content.bmc.customer_segments = Array.isArray(content.bmc.customer_segments) ? content.bmc.customer_segments : [];
content.bmc.value_propositions = Array.isArray(content.bmc.value_propositions) ? content.bmc.value_propositions : [];
content.bmc.channels = Array.isArray(content.bmc.channels) ? content.bmc.channels : [];
content.bmc.customer_relationships = Array.isArray(content.bmc.customer_relationships) ? content.bmc.customer_relationships : [];
content.bmc.revenue_streams = Array.isArray(content.bmc.revenue_streams) ? content.bmc.revenue_streams : [];
content.bmc.key_resources = Array.isArray(content.bmc.key_resources) ? content.bmc.key_resources : [];
content.bmc.key_activities = Array.isArray(content.bmc.key_activities) ? content.bmc.key_activities : [];
content.bmc.key_partners = Array.isArray(content.bmc.key_partners) ? content.bmc.key_partners : [];
content.bmc.cost_structure = Array.isArray(content.bmc.cost_structure) ? content.bmc.cost_structure : [];

content.positioning = content.positioning || {};
content.positioning.problem_statement = content.positioning.problem_statement || "";
content.positioning.differentiators = Array.isArray(content.positioning.differentiators) ? content.positioning.differentiators : [];
content.positioning.fit_score = typeof content.positioning.fit_score === 'number' ? content.positioning.fit_score : 0;
content.positioning.assumptions = Array.isArray(content.positioning.assumptions) ? content.positioning.assumptions : [];

return [{ json: content }];

const data = $json;

if (!data.bmc || typeof data.bmc !== 'object') {
  throw new Error('bmc faltante o inválido');
}

if (!data.positioning || typeof data.positioning !== 'object') {
  throw new Error('positioning faltante o inválido');
}

return [{ json: data }];
